import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    pink: '#f472b6',
    green: '#10b981',
    red: '#f43f5e',
    yellow: '#fbbf24',
    orange: '#fb923c',
    purple: '#a78bfa',
  },
  font: "'JetBrains Mono', monospace",
};

const presets = [
  { name: 'Default', joint: 50, x: 200, y: 300, desc: 'Slightly less than expected' },
  { name: 'Independent', joint: 60, x: 200, y: 300, desc: 'Events are independent' },
  { name: 'Strong +', joint: 150, x: 200, y: 300, desc: 'Strong positive association' },
  { name: 'Rare overlap', joint: 10, x: 200, y: 300, desc: 'Rarely co-occur' },
  { name: 'Never', joint: 0, x: 200, y: 300, desc: 'Never co-occur' },
];

const TOTAL = 1000;

export default function App() {
  const [jointCount, setJointCount] = useState(50);
  const [countX, setCountX] = useState(200);
  const [countY, setCountY] = useState(300);
  const [animPulse, setAnimPulse] = useState(0);
  const [hoveredSection, setHoveredSection] = useState(null);

  useEffect(() => {
    const iv = setInterval(() => setAnimPulse(p => (p + 1) % 120), 40);
    return () => clearInterval(iv);
  }, []);

  const maxJoint = Math.min(countX, countY);
  const safeJoint = Math.min(jointCount, maxJoint);

  const pX = countX / TOTAL;
  const pY = countY / TOTAL;
  const pXY = safeJoint / TOTAL;
  const expected = pX * pY;
  const expectedCount = Math.round(expected * TOTAL);
  const pmi = pXY === 0 ? null : Math.log2(pXY / (pX * pY));
  const pmiRounded = pmi !== null ? Math.round(pmi * 1000) / 1000 : null;

  const pmiColor = pmi === null ? theme.colors.textMuted
    : pmi > 0.05 ? theme.colors.green
    : pmi < -0.05 ? theme.colors.red
    : theme.colors.yellow;

  const interpretation = pmi === null
    ? 'Events never co-occur (PMI = -infinity)'
    : pmi > 0.5 ? 'Strong positive association - co-occur much more than expected!'
    : pmi > 0.05 ? 'Positive association - co-occur more than expected by chance'
    : pmi > -0.05 ? 'Approximately independent - co-occurrence matches expectation'
    : pmi > -0.5 ? 'Negative association - co-occur less than expected'
    : 'Strong negative association - rarely co-occur together';

  const handlePreset = (p) => {
    setJointCount(p.joint);
    setCountX(p.x);
    setCountY(p.y);
  };

  const handleReset = () => {
    setJointCount(50);
    setCountX(200);
    setCountY(300);
  };

  // SVG dimensions
  const W = 560, H = 200;
  const barAreaTop = 30;
  const barH = 56;
  const barMaxW = 400;
  const barLeft = 110;

  const maxP = Math.max(expected, pXY, 0.001);
  const scale = barMaxW / Math.max(maxP * 1.3, 0.01);

  const expectedBarW = Math.max(expected * scale, 2);
  const actualBarW = pXY === 0 ? 2 : Math.max(pXY * scale, 2);

  const pulseGlow = 0.15 + 0.1 * Math.sin(animPulse * 0.08);

  // Venn diagram params
  const vennCx1 = 200, vennCx2 = 340, vennCy = 110, vennR = 90;
  const overlapFraction = maxJoint > 0 ? safeJoint / maxJoint : 0;
  const maxOverlapDist = vennR * 2;
  const dist = maxOverlapDist * (1 - overlapFraction * 0.7);
  const cx1 = 270 - dist / 2;
  const cx2 = 270 + dist / 2;

  const xOnly = countX - safeJoint;
  const yOnly = countY - safeJoint;
  const neither = TOTAL - xOnly - yOnly - safeJoint;

  return (
    <div style={{
      maxWidth: 600,
      margin: '0 auto',
      padding: '16px 14px',
      fontFamily: theme.font,
      background: theme.colors.background,
      color: theme.colors.text,
      minHeight: '100vh',
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700 }}>Pointwise Mutual Information</div>
          <div style={{ fontSize: 11, color: theme.colors.textMuted, marginTop: 2 }}>Drag the joint count to explore PMI</div>
        </div>
        <button onClick={handleReset} style={{
          background: theme.colors.surfaceAlt, border: '1px solid ' + theme.colors.border,
          color: theme.colors.textSecondary, borderRadius: 6, padding: '5px 12px',
          cursor: 'pointer', fontSize: 11, fontFamily: theme.font,
        }}>Reset</button>
      </div>

      {/* Presets */}
      <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
        {presets.map((p, i) => {
          const active = safeJoint === p.joint && countX === p.x && countY === p.y;
          return (
            <button key={i} onClick={() => handlePreset(p)} style={{
              background: active ? theme.colors.primary + '22' : theme.colors.surface,
              border: '1px solid ' + (active ? theme.colors.primary : theme.colors.border),
              color: active ? theme.colors.primary : theme.colors.textSecondary,
              borderRadius: 6, padding: '4px 10px', cursor: 'pointer',
              fontSize: 10, fontFamily: theme.font, transition: 'all 0.2s',
            }}>{p.name}</button>
          );
        })}
      </div>

      {/* Main Visualization: Venn Diagram */}
      <div style={{
        background: theme.colors.surface, borderRadius: 10,
        border: '1px solid ' + theme.colors.border, marginBottom: 12,
        overflow: 'hidden',
      }}>
        <svg width="100%" viewBox={`0 0 540 230`} style={{ display: 'block' }}>
          <defs>
            <clipPath id="clipX">
              <circle cx={cx1} cy={vennCy} r={vennR} />
            </clipPath>
            <clipPath id="clipY">
              <circle cx={cx2} cy={vennCy} r={vennR} />
            </clipPath>
            <clipPath id="clipBoth">
              <circle cx={cx1} cy={vennCy} r={vennR} />
            </clipPath>
          </defs>

          {/* Background label */}
          <text x={270} y={18} textAnchor="middle" fill={theme.colors.textMuted} fontSize={10} fontFamily={theme.font}>
            Total Samples: {TOTAL}
          </text>

          {/* Circle X */}
          <circle cx={cx1} cy={vennCy} r={vennR}
            fill={theme.colors.blue + '18'}
            stroke={hoveredSection === 'x' ? theme.colors.blue : theme.colors.blue + '55'}
            strokeWidth={hoveredSection === 'x' ? 2.5 : 1.5}
            style={{ transition: 'all 0.3s', cursor: 'default' }}
            onMouseEnter={() => setHoveredSection('x')}
            onMouseLeave={() => setHoveredSection(null)}
          />

          {/* Circle Y */}
          <circle cx={cx2} cy={vennCy} r={vennR}
            fill={theme.colors.pink + '18'}
            stroke={hoveredSection === 'y' ? theme.colors.pink : theme.colors.pink + '55'}
            strokeWidth={hoveredSection === 'y' ? 2.5 : 1.5}
            style={{ transition: 'all 0.3s', cursor: 'default' }}
            onMouseEnter={() => setHoveredSection('y')}
            onMouseLeave={() => setHoveredSection(null)}
          />

          {/* Overlap region */}
          {safeJoint > 0 && (
            <circle cx={cx2} cy={vennCy} r={vennR}
              clipPath="url(#clipBoth)"
              fill={theme.colors.purple + (hoveredSection === 'joint' ? '55' : '33')}
              stroke="none"
              style={{ transition: 'all 0.3s', cursor: 'default' }}
              onMouseEnter={() => setHoveredSection('joint')}
              onMouseLeave={() => setHoveredSection(null)}
            />
          )}

          {/* Labels */}
          <text x={cx1 - 30} y={vennCy - 12} textAnchor="middle" fill={theme.colors.blue} fontSize={12} fontWeight={700} fontFamily={theme.font}>
            Event X
          </text>
          <text x={cx1 - 30} y={vennCy + 6} textAnchor="middle" fill={theme.colors.blue + 'bb'} fontSize={11} fontFamily={theme.font}>
            {countX}
          </text>
          <text x={cx1 - 30} y={vennCy + 20} textAnchor="middle" fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font}>
            P={pX.toFixed(2)}
          </text>

          <text x={cx2 + 30} y={vennCy - 12} textAnchor="middle" fill={theme.colors.pink} fontSize={12} fontWeight={700} fontFamily={theme.font}>
            Event Y
          </text>
          <text x={cx2 + 30} y={vennCy + 6} textAnchor="middle" fill={theme.colors.pink + 'bb'} fontSize={11} fontFamily={theme.font}>
            {countY}
          </text>
          <text x={cx2 + 30} y={vennCy + 20} textAnchor="middle" fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font}>
            P={pY.toFixed(2)}
          </text>

          {/* Joint label in center */}
          <text x={(cx1 + cx2) / 2} y={vennCy - 8} textAnchor="middle" fill={theme.colors.purple} fontSize={11} fontWeight={700} fontFamily={theme.font}
            style={{ transition: 'all 0.3s' }}>
            {safeJoint > 0 ? 'Both' : '--'}
          </text>
          <text x={(cx1 + cx2) / 2} y={vennCy + 8} textAnchor="middle" fill={theme.colors.purple + 'cc'} fontSize={13} fontWeight={700} fontFamily={theme.font}
            style={{ transition: 'all 0.3s' }}>
            {safeJoint}
          </text>
          <text x={(cx1 + cx2) / 2} y={vennCy + 22} textAnchor="middle" fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font}>
            P={pXY.toFixed(3)}
          </text>

          {/* Expected indicator */}
          <text x={270} y={215} textAnchor="middle" fill={theme.colors.textMuted} fontSize={10} fontFamily={theme.font}>
            Expected if independent: {expectedCount} (P={expected.toFixed(3)}) | Actual: {safeJoint} (P={pXY.toFixed(3)})
          </text>
        </svg>
      </div>

      {/* Main Slider: Joint Count */}
      <div style={{
        background: theme.colors.surface, borderRadius: 10, padding: '14px 16px',
        border: '1px solid ' + theme.colors.border, marginBottom: 12,
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
          <span style={{ fontSize: 12, fontWeight: 600, color: theme.colors.purple }}>Joint Count (X and Y together)</span>
          <span style={{
            fontSize: 18, fontWeight: 800, color: theme.colors.purple,
            background: theme.colors.purple + '15', padding: '2px 10px', borderRadius: 6,
          }}>{safeJoint}</span>
        </div>
        <input type="range" min={0} max={maxJoint} value={safeJoint}
          onChange={e => setJointCount(parseInt(e.target.value))}
          style={{ width: '100%', accentColor: theme.colors.purple, cursor: 'pointer' }} />
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.colors.textMuted, marginTop: 2 }}>
          <span>0 (never)</span>
          <span style={{ color: theme.colors.yellow }}>^ {expectedCount} expected if independent</span>
          <span>{maxJoint} (max)</span>
        </div>
      </div>

      {/* Expected vs Actual Comparison */}
      <div style={{
        background: theme.colors.surface, borderRadius: 10, padding: '12px 16px',
        border: '1px solid ' + theme.colors.border, marginBottom: 12,
      }}>
        <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 10, textTransform: 'uppercase', letterSpacing: 1 }}>Expected vs Actual</div>

        {/* Expected bar */}
        <div style={{ marginBottom: 8 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 3 }}>
            <span style={{ fontSize: 10, color: theme.colors.textSecondary, width: 70 }}>Expected</span>
            <div style={{ flex: 1, height: 22, background: theme.colors.surfaceAlt, borderRadius: 4, position: 'relative', overflow: 'hidden' }}>
              <div style={{
                height: '100%', borderRadius: 4,
                width: `${Math.min((expected / Math.max(maxP * 1.3, 0.001)) * 100, 100)}%`,
                background: theme.colors.yellow + '44',
                border: '1px dashed ' + theme.colors.yellow + '88',
                transition: 'width 0.3s ease',
                display: 'flex', alignItems: 'center', paddingLeft: 6,
              }}>
                <span style={{ fontSize: 10, color: theme.colors.yellow, fontWeight: 600 }}>{expected.toFixed(4)}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Actual bar */}
        <div style={{ marginBottom: 4 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 3 }}>
            <span style={{ fontSize: 10, color: theme.colors.textSecondary, width: 70 }}>Actual</span>
            <div style={{ flex: 1, height: 22, background: theme.colors.surfaceAlt, borderRadius: 4, position: 'relative', overflow: 'hidden' }}>
              <div style={{
                height: '100%', borderRadius: 4,
                width: pXY === 0 ? '1%' : `${Math.min((pXY / Math.max(maxP * 1.3, 0.001)) * 100, 100)}%`,
                background: pmiColor + '33',
                border: '1px solid ' + pmiColor + '88',
                transition: 'all 0.3s ease',
                display: 'flex', alignItems: 'center', paddingLeft: 6,
              }}>
                <span style={{ fontSize: 10, color: pmiColor, fontWeight: 600 }}>{pXY.toFixed(4)}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Formula line */}
        <div style={{
          fontSize: 10, color: theme.colors.textMuted, textAlign: 'center',
          marginTop: 8, padding: '6px 0', borderTop: '1px solid ' + theme.colors.border,
          fontFamily: theme.font,
        }}>
          PMI = log2( <span style={{ color: theme.colors.purple }}>{pXY.toFixed(4)}</span>
          {' / ('}<span style={{ color: theme.colors.blue }}>{pX.toFixed(2)}</span>
          {' * '}<span style={{ color: theme.colors.pink }}>{pY.toFixed(2)}</span>
          {') ) = log2( '}<span style={{ color: theme.colors.purple }}>{pXY.toFixed(4)}</span>
          {' / '}<span style={{ color: theme.colors.yellow }}>{(pX * pY).toFixed(4)}</span>
          {' ) = '}
          <span style={{ color: pmiColor, fontWeight: 700, fontSize: 12 }}>
            {pmi === null ? '-inf' : pmiRounded.toFixed(3)}
          </span>
        </div>
      </div>

      {/* PMI Result */}
      <div style={{
        background: theme.colors.surface, borderRadius: 10, padding: '14px 16px',
        border: '1px solid ' + pmiColor + '44', marginBottom: 12,
        textAlign: 'center', transition: 'border-color 0.3s',
      }}>
        <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 6, textTransform: 'uppercase', letterSpacing: 1 }}>Result</div>
        <div style={{
          fontSize: 32, fontWeight: 800, color: pmiColor,
          transition: 'color 0.3s',
          textShadow: `0 0 20px ${pmiColor}${Math.round(pulseGlow * 255).toString(16).padStart(2, '0')}`,
        }}>
          {pmi === null ? '-inf' : pmiRounded.toFixed(3)}
        </div>
        <div style={{ fontSize: 11, color: pmiColor + 'cc', marginTop: 4, transition: 'color 0.3s' }}>
          {interpretation}
        </div>
      </div>

      {/* Secondary Controls */}
      <div style={{
        display: 'flex', gap: 8, marginBottom: 12,
      }}>
        <div style={{
          flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '10px 12px',
          border: '1px solid ' + theme.colors.border,
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
            <span style={{ fontSize: 10, color: theme.colors.blue }}>Count X</span>
            <span style={{ fontSize: 12, fontWeight: 700, color: theme.colors.blue }}>{countX}</span>
          </div>
          <input type="range" min={10} max={800} value={countX}
            onChange={e => {
              const v = parseInt(e.target.value);
              setCountX(v);
              if (jointCount > Math.min(v, countY)) setJointCount(Math.min(v, countY));
            }}
            style={{ width: '100%', accentColor: theme.colors.blue }} />
        </div>
        <div style={{
          flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '10px 12px',
          border: '1px solid ' + theme.colors.border,
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
            <span style={{ fontSize: 10, color: theme.colors.pink }}>Count Y</span>
            <span style={{ fontSize: 12, fontWeight: 700, color: theme.colors.pink }}>{countY}</span>
          </div>
          <input type="range" min={10} max={800} value={countY}
            onChange={e => {
              const v = parseInt(e.target.value);
              setCountY(v);
              if (jointCount > Math.min(countX, v)) setJointCount(Math.min(countX, v));
            }}
            style={{ width: '100%', accentColor: theme.colors.pink }} />
        </div>
      </div>

      {/* Key Insight */}
      <div style={{
        padding: '10px 14px', background: theme.colors.surface, borderRadius: 8,
        fontSize: 10, color: theme.colors.textSecondary, textAlign: 'center',
        borderLeft: '3px solid ' + pmiColor, transition: 'border-color 0.3s',
      }}>
        <strong style={{ color: theme.colors.text }}>Key insight:</strong>{' '}
        PMI compares actual co-occurrence to expected co-occurrence under independence. When actual {'>'} expected, PMI is positive. When actual {'<'} expected, PMI is negative.
      </div>
    </div>
  );
}
